{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-plus-pump-parameter-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "summary": "当前围绕两个已选中对象生成候选提案：一是针对未连接的流股 cooler-outlet-81 提供最小拓扑占位建议，二是针对泵 pump-12 的出口压力目标与效率参数提供局部参数修正建议。由于诊断明确要求 cooler-12 本体仅作为说明性上下文，且当前快照显示拓扑无效，因此提案限制在直接有诊断支撑的流股与泵参数上。",
  "issues": [
    {
      "title": "未连接的冷却器出口流股需要下游占位",
      "detail": "cooler-outlet-81 当前没有任何下游消费者或导出端，导致拓扑无效；在缺乏具体下游对象证据时，只适合补充非执行式连接占位。",
      "citations": [
        "diag-1",
        "flowdoc-stream-3",
        "snapshot-1"
      ]
    },
    {
      "title": "泵出口压力目标低于入口压力",
      "detail": "pump-12 的 outlet_pressure_target_kpa=150 低于其入口流股 feed-81 的 pressure_kpa=190，直接触发压力目标无效诊断。",
      "citations": [
        "diag-2",
        "flowdoc-unit-1",
        "flowdoc-stream-1"
      ]
    },
    {
      "title": "泵效率参数超出推荐范围",
      "detail": "pump-12 的 efficiency_percent=108 已被标记为超出推荐运行范围，适合改为待确认的参数占位或保守回调。",
      "citations": [
        "diag-3",
        "flowdoc-unit-1"
      ]
    }
  ],
  "answers": [
    {
      "summary": "建议先用最小可审查 patch 处理 cooler-outlet-81 的下游连接占位，再对 pump-12 提交两个局部参数修正候选；不对 cooler-12 本体控制方式或出口状态做主动修改。",
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Trim Cooler Outlet 添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "cooler-outlet-81"
          },
          "rationale": "诊断仅确认该流股缺少下游消费者或导出端，但未提供具体接收对象。为避免凭空指定设备，建议仅增加一个待确认的下游连接占位，以便后续由人工补齐真实去向。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "cooler-outlet-81",
              "missing_end": "downstream",
              "allowed_connection_kinds": [
                "unit_inlet",
                "export_sink"
              ],
              "prompt": "请确认 Trim Cooler Outlet 的真实下游去向，并补齐连接。"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "将 Recycle Pump 出口压力目标改为高于入口压力的待确认值",
          "target": {
            "type": "unit",
            "id": "pump-12"
          },
          "rationale": "当前 outlet_pressure_target_kpa=150 低于入口流股 pressure_kpa=190，违反泵升压方向。为保持最小改动且不武断指定工艺值，建议把该参数替换为必须大于 190 kPa 的待确认占位。",
          "patch": {
            "spec_placeholders": [
              {
                "path": "config.outlet_pressure_target_kpa",
                "kind": "numeric_min_exclusive",
                "min_exclusive": 190,
                "unit": "kPa",
                "prompt": "请确认 Recycle Pump 的目标出口压力，需高于入口压力 190 kPa。"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "将 Recycle Pump 效率改为范围内的待确认参数",
          "target": {
            "type": "unit",
            "id": "pump-12"
          },
          "rationale": "efficiency_percent=108 已超出推荐范围。现有证据未给出唯一正确值，因此建议提交一个局部参数占位，要求人工确认并回填至合理区间内。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.efficiency_percent",
                "kind": "bounded_numeric",
                "min": 0,
                "max": 100,
                "unit": "%",
                "prompt": "请确认 Recycle Pump 的效率设定，当前 108% 超出推荐范围。"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1"
          ]
        }
      ],
      "citations": [
        "diag-1",
        "diag-2",
        "diag-3",
        "diag-4",
        "flowdoc-stream-3",
        "flowdoc-unit-1",
        "flowdoc-unit-2",
        "snapshot-1"
      ],
      "confidence": 0.9
    }
  ]
}
